import { HttpClient } from "@angular/common/http";
import {
  AfterViewInit,
  ChangeDetectorRef,
  Component,
  OnInit,
  Renderer2,
  NgZone,
  ViewChild,
} from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { AlertController, IonInput, Platform } from "@ionic/angular";
import { AlertService } from "src/app/core/services/alert.service";
import { EnvService } from "src/app/core/services/env.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { IBankSafe } from "src/app/views/Models/Loan/BankSafe";
import { Funders } from "src/app/views/Models/References/Funders";
import { IInsurance } from "src/app/views/Models/References/Insurance";
import { IIssuingBank } from "src/app/views/Models/Loan/IssuingBank";
import { IMakingLoanInsert } from "src/app/views/Models/Loan/MakingLoan";
import { ScrollingService } from "src/app/core/services/scrolling.service";
import { IMakingLoanSearchPerClient } from "src/app/views/Models/Loan/MakingLoan";
import { Subscription } from "rxjs";
import { Router } from "@angular/router";
import { format } from "date-fns";
import { SMSService } from "src/app/core/services/sms.service";
import { ReferencesService } from "src/app/core/services/references.service";

@Component({
  selector: "app-making-loan-per-client",
  templateUrl: "./making-loan-per-client.page.html",
  styleUrls: ["./making-loan-per-client.page.scss"],
})
export class MakingLoanPerClientPage implements OnInit {
  constructor(
    public formBuilder: FormBuilder,
    private env: EnvService,
    private http: HttpClient,
    private authService: MohassilAuthService,
    private ScrollingService: ScrollingService,
    private router: Router,
    private platform: Platform,
    private alertSerivce: AlertService,
    private referencesService: ReferencesService
  ) {}

  //#region Variables
  showLoader: boolean = false;
  isSearchForm: boolean = true;
  isGridForm: boolean = false;
  isMakingLoanForm: boolean = false;
  isMakingLoanFormValid: boolean = false;
  isSearchLoanFormValid: boolean = false;
  org_code_user_info: string;
  allApplications: IMakingLoanSearchPerClient[];
  IMakingLoanSearch: IMakingLoanSearchPerClient;
  IIssuingBank: IIssuingBank[];
  IBankSafe: IBankSafe[];
  IInsurance: IInsurance[];
  Funders: Funders[];
  FundingRef: any;
  iscore_external_funding: any;
  isIscore_external_funding: boolean;
  backButtonListener: Subscription;
  searchTypes = [
    [" البحث بالرقم القومى", "1"],
    ["البحث بكود العميل", "2"],
    ["البحث برقم التليفون", "3"],
  ];
  //#endregion

  async ngOnInit() {
    await this.authService.getUserInfo().then((userInfo) => {
      this.org_code_user_info = userInfo.org_code;
    });
    this.registerBackButtonListener();
    this.IIssuingBank = await this.referencesService.getAllIssuingBanks();
    this.IBankSafe = await this.referencesService.getAllBanksSafe();
    this.IInsurance = await this.referencesService.getAllInsurances();
    this.Funders = await this.referencesService.getAllFunders();
  }
  funderCodeChange($event) {
    if ($event.detail.value != "") {
      this.makingLoanForm.patchValue({ funding_reference_id: null });
      this.checkFundingReference($event.detail.value);
    }
  }
  checkFundingReference(funder_code: string) {
    this.showLoader = true;
    this.http
      .post(this.env.API_URL + "api/LoanApplications/GetFundingReference", {
        org_code: this.org_code_user_info,
        funder_code: funder_code,
      })
      .subscribe({
        next: (data) => {
          console.log(data);
          this.FundingRef = data["fundingRefs"];
          this.iscore_external_funding = data["iscore_external_funding"];
          if (this.iscore_external_funding == "1") {
            this.isIscore_external_funding = true;
            this.makingLoanForm.controls["funding_reference_id"].setValidators([
              Validators.required,
            ]);
          } else {
            this.isIscore_external_funding = false;
            this.makingLoanForm.controls[
              "funding_reference_id"
            ].clearValidators();
          }
          this.makingLoanForm.controls[
            "funding_reference_id"
          ].updateValueAndValidity();
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err);
          this.showLoader = false;
        },
      });
  }
  clientSearch() {
    this.isSearchLoanFormValid = true;
    if (this.searchForm.valid) {
      this.showLoader = true;
      let searchtypeValue: string =
        this.searchForm.controls["search_type"].value;
      let searchInputValue: string =
        this.searchForm.controls["search_input"].value;

      this.http
        .post<IMakingLoanSearchPerClient[]>(
          this.env.API_URL + "api/LoanApplications/GetMakingLoanPerClient",
          {
            nation_id: searchtypeValue == "1" ? searchInputValue : null,
            branch_code:
              searchtypeValue == "2"
                ? searchInputValue.substring(0, searchInputValue.indexOf("/"))
                : null,
            client_code:
              searchtypeValue == "2"
                ? searchInputValue.slice(searchInputValue.indexOf("/") + 1)
                : null,
            mobile: searchtypeValue == "3" ? searchInputValue : null,
          }
        )
        .subscribe({
          next: (data) => {
            if (data.length == 0) {
              this.alertSerivce.showAlertError("لا يوجد قروض للانشاء", false);
              this.showLoader = false;
              return;
            } else if (data.length == 1) {
              this.IMakingLoanSearch = data[0];
              this.allApplications = data;
              this.isSearchForm = false;
              this.isMakingLoanForm = true;
              this.PatchingSpecificLoan(this.allApplications[0]);
            } else if (data.length >= 1) {
              this.allApplications = data;
              for (let i = 0; i < this.allApplications.length; i++) {
                this.allApplications[i].com_dec_date = format(
                  new Date(this.allApplications[i].com_dec_date),
                  "yyyy-MM-dd"
                );
              }
              this.isSearchForm = false;
              this.isGridForm = true;
            }

            this.showLoader = false;
          },
          error: (err) => {
            console.log(err);
            this.alertSerivce.showAlertError(err.error, false);
            this.showLoader = false;
          },
        });
    }
  }
  PatchingSpecificLoan(loanObject: IMakingLoanSearchPerClient) {
    loanObject.funder_code == null
      ? null
      : this.checkFundingReference(loanObject.funder_code.toString());
    this.makingLoanForm.patchValue({
      client_name: loanObject.client_name,
      nation_id: loanObject.nation_id,
      aprv_am: loanObject.aprv_am,
      clnt_code: loanObject.clnt_code,
      loan_type_name: loanObject.loan_type_name,
      client_type_name: loanObject.client_type_name,
      loan_int_rt: loanObject.loan_int_rt,
      payments_shift: loanObject.payments_shift,
      com_dec_date: loanObject.com_dec_date,
      funder_code:
        loanObject.funder_code == null
          ? null
          : loanObject.funder_code.toString(),
      funding_reference_id:
        loanObject.funding_reference_id == null
          ? null
          : loanObject.funding_reference_id.toString(),
    });
  }
  selectedApplication(loan: IMakingLoanSearchPerClient, i: number) {
    this.PatchingSpecificLoan(
      this.allApplications.filter(
        (x) => x.application_key == loan.application_key
      )[0]
    );
    this.IMakingLoanSearch = loan;
    this.isGridForm = false;
    this.isMakingLoanForm = true;
  }
  searchTypeChange() {
    this.searchForm.patchValue({ search_input: null });
    let searchInput = this.searchForm.controls["search_input"];
    let searchType = this.searchForm.controls["search_type"];
    if (searchType.value == "1") {
      searchInput.setValidators([
        Validators.pattern(
          "^([1-9]{1})([0-9]{2})([0-9]{2})([0-9]{2})([0-9]{2})[0-9]{3}([0-9]{1})[0-9]{1}$"
        ),
        Validators.required,
      ]);
    } else if (searchType.value == "2") {
      searchInput.setValidators([
        Validators.pattern("([0-9]{1,3})/([0-9]{1,7})$"),
        Validators.required,
      ]);
    } else if (searchType.value == "3") {
      searchInput.setValidators([
        Validators.pattern("^01[0125][0-9]{8}$"),
        Validators.required,
      ]);
    }
    searchInput.updateValueAndValidity();
  }
  async makingLoan() {
    this.isMakingLoanFormValid = true;
    if (!this.makingLoanForm.valid) {
      await this.ScrollingService.findInvalidControls(this.makingLoanForm);
    }
    if (!(await this.alertSerivce.SaveAlert())) {
      return;
    }
    this.showLoader = true;
    let sendingObject = {
      application_key: this.IMakingLoanSearch.application_key.toString(),
      dec_effective_date:
        this.makingLoanForm.controls["dec_effective_date"].value,
      issuingbank: this.makingLoanForm.controls["issuingbank"].value.toString(),
      bankSafe: this.makingLoanForm.controls["bankSafe"].value.toString(),
      payments_shift:
        this.makingLoanForm.controls["payments_shift"].value == null
          ? null
          : this.makingLoanForm.controls["payments_shift"].value.toString(),
      funder_code: this.makingLoanForm.controls["funder_code"].value,
      funding_reference_id:
        this.makingLoanForm.controls["funding_reference_id"].value,
      loan_vouch_char: this.makingLoanForm.controls["loan_vouch_char"].value,
      uuc: this.IMakingLoanSearch.uuc,
    };

    this.http
      .post<IMakingLoanInsert[]>(
        this.env.API_URL + "api/LoanApplications/MakingLoanInsert",
        {
          loan_vouch_char: sendingObject.loan_vouch_char,
          dec_effective_date: sendingObject.dec_effective_date,
          bank_code: sendingObject.issuingbank,
          inst_cur_bank: sendingObject.bankSafe,
          payments_shift: sendingObject.payments_shift,
          application_key: sendingObject.application_key,
          funder_code: sendingObject.funder_code,
          funding_reference_id: sendingObject.funding_reference_id,
          uuc: sendingObject.uuc.toString(),
        }
      )
      .subscribe({
        next: async (data) => {
          await this.alertSerivce.showAlertConfirm(
            "لقد تم الانشاء بنجاح",
            true
          );
          this.showLoader = false;
        },
        error: async (err) => {
          await this.alertSerivce.showAlertError(err.error, false);
          this.showLoader = false;
        },
      });
  }
  backToSearchForm() {
    this.showLoader = true;
    this.searchForm.patchValue({ search_type: "1" });
    this.searchForm.patchValue({ search_input: null });
    this.searchForm.patchValue({ issuingbank: "" });
    this.searchForm.patchValue({ bankSafe: "" });
    this.searchForm.patchValue({ inssurance: "" });
    this.searchForm.patchValue({ funder_code: "" });
    this.searchForm.patchValue({ funding_reference_id: "" });
    this.searchForm.patchValue({ loan_vouch_char: "" });
    this.searchTypeChange();
    this.allApplications = null;
    this.isMakingLoanForm = false;
    this.isGridForm = false;
    this.isMakingLoanFormValid = false;
    this.isSearchLoanFormValid = false;
    this.isSearchForm = true;
    this.showLoader = false;
  }
  backToGridForm() {
    if (this.allApplications.length > 1) {
      this.isMakingLoanForm = false;
      this.isGridForm = true;
      this.isMakingLoanFormValid = false;
    } else {
      this.backToSearchForm();
    }
  }
  registerBackButtonListener(): void {
    this.backButtonListener = this.platform.backButton.subscribeWithPriority(
      10,
      (next) => {
        this.backButton();
      }
    );
  }
  backButton(): void {
    if (this.isSearchForm == true) {
      this.router.navigate(["/home"]);
    } else if (this.isMakingLoanForm) {
      this.backToSearchForm();
    }
  }
  enterClick(event: KeyboardEvent) {
    if (event.key == "Enter") {
      this.clientSearch();
    }
  }
  get GetSearchLoanForm() {
    return this.searchForm.controls;
  }
  get GetMakingLoanForm() {
    return this.makingLoanForm.controls;
  }
  searchForm: FormGroup = this.formBuilder.group({
    search_type: ["1", Validators.required],
    search_input: [
      null,
      [
        Validators.required,
        Validators.pattern(
          "^([1-9]{1})([0-9]{2})([0-9]{2})([0-9]{2})([0-9]{2})[0-9]{3}([0-9]{1})[0-9]{1}$"
        ),
      ],
    ],
  });
  makingLoanForm: FormGroup = this.formBuilder.group({
    client_name: [""],
    nation_id: [""],
    aprv_am: [""],
    clnt_code: [""],
    loan_type_name: [""],
    client_type_name: [""],
    loan_int_rt: [""],
    payments_shift: [""],
    com_dec_date: [""],
    dec_effective_date: [""],
    issuingbank: ["", Validators.required],
    bankSafe: ["", Validators.required],
    inssurance: [""],
    funder_code: ["", Validators.required],
    funding_reference_id: [""],
    loan_vouch_char: [""],
  });
  gridForm: FormGroup = this.formBuilder.group({});
}
